package connector

import (
	"context"
	"crypto/aes"
	"crypto/cipher"
	"crypto/rand"
	"crypto/sha256"
	"encoding/json"
	"fmt"
	"io"
	"os"
	"strings"

	"golang.org/x/oauth2"
	"golang.org/x/oauth2/google"
)

// deriveLocalKey creates a deterministic key from machine-specific data.
// This is not perfect security but prevents casual file theft.
func deriveLocalKey() []byte {
	hostname, _ := os.Hostname()
	home, _ := os.UserHomeDir()
	material := hostname + ":" + home + ":nurge-local-creds"
	h := sha256.Sum256([]byte(material))
	return h[:]
}

// encryptLocal encrypts plaintext using AES-GCM with a machine-derived key.
func encryptLocal(plaintext []byte) ([]byte, error) {
	key := deriveLocalKey()
	block, err := aes.NewCipher(key)
	if err != nil {
		return nil, err
	}
	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return nil, err
	}
	nonce := make([]byte, gcm.NonceSize())
	if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
		return nil, err
	}
	return gcm.Seal(nonce, nonce, plaintext, nil), nil
}

// decryptLocal decrypts ciphertext using AES-GCM with a machine-derived key.
func decryptLocal(ciphertext []byte) ([]byte, error) {
	key := deriveLocalKey()
	block, err := aes.NewCipher(key)
	if err != nil {
		return nil, err
	}
	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return nil, err
	}
	nonceSize := gcm.NonceSize()
	if len(ciphertext) < nonceSize {
		return nil, fmt.Errorf("ciphertext too short")
	}
	nonce, ct := ciphertext[:nonceSize], ciphertext[nonceSize:]
	return gcm.Open(nil, nonce, ct, nil)
}

// readEncryptedCredentials reads a credentials file, decrypting if needed.
// For backwards compatibility, if decryption fails it assumes plaintext JSON
// (old format) and returns the raw data.
func readEncryptedCredentials(path string) ([]byte, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, err
	}
	// Try to decrypt first (new encrypted format).
	if decrypted, err := decryptLocal(data); err == nil {
		return decrypted, nil
	}
	// Decryption failed - assume plaintext JSON (old format).
	return data, nil
}

// writeEncryptedCredentials encrypts data and writes it atomically to path.
func writeEncryptedCredentials(path string, data []byte) error {
	encrypted, err := encryptLocal(data)
	if err != nil {
		return fmt.Errorf("encrypting credentials: %w", err)
	}
	tmpPath := path + ".tmp"
	if err := os.WriteFile(tmpPath, encrypted, 0600); err != nil {
		return err
	}
	if err := os.Rename(tmpPath, path); err != nil {
		os.Remove(tmpPath)
		return err
	}
	return nil
}

func (g *GenericConnector) connectOAuth2(ctx context.Context) (*Result, error) {
	var oauthCfg *oauth2.Config
	var authOpts []oauth2.AuthCodeOption

	if g.def.Credentials.Source == "google_json" {
		// Google-specific: use google.ConfigFromJSON
		credsData, err := g.loadGoogleCredentials()
		if err != nil {
			return nil, err
		}
		cfg, err := google.ConfigFromJSON(credsData, g.def.Auth.Scopes...)
		if err != nil {
			return nil, fmt.Errorf("parsing Google credentials: %w", err)
		}
		oauthCfg = cfg
	} else {
		// Generic OAuth2: build config from YAML
		clientID, clientSecret, err := g.resolveOAuthCredentials()
		if err != nil {
			return nil, err
		}
		cfg, opts, err := g.buildOAuthConfig(clientID, clientSecret)
		if err != nil {
			return nil, err
		}
		oauthCfg = cfg
		authOpts = opts
	}

	// Check for ExtraParams key conflicts with PKCE params
	pkceReserved := map[string]bool{"code_challenge": true, "code_challenge_method": true, "code_verifier": true}
	for k := range g.def.Auth.ExtraParams {
		if pkceReserved[k] {
			return nil, fmt.Errorf("connector %q: extra_params key %q conflicts with PKCE parameters", g.def.ID, k)
		}
	}

	// Add extra_params as auth options for google_json too
	if g.def.Credentials.Source == "google_json" {
		for k, v := range g.def.Auth.ExtraParams {
			authOpts = append(authOpts, oauth2.SetAuthURLParam(k, v))
		}
	}

	// Run shared OAuth flow
	token, err := OAuthFlow(ctx, oauthCfg, authOpts...)
	if err != nil {
		return nil, err
	}

	// Save token atomically (write to tmp, then rename)
	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
	tokenPath := tokenDir + "/token.json"
	if err := os.MkdirAll(tokenDir, 0700); err != nil {
		return nil, fmt.Errorf("creating connector dir: %w", err)
	}
	if err := saveTokenAtomic(tokenPath, token); err != nil {
		return nil, fmt.Errorf("saving token: %w", err)
	}

	// Save granted scopes for later scope-sufficiency checks
	if len(g.def.Auth.Scopes) > 0 {
		if scopeErr := SaveGrantedScopes(tokenDir, g.def.Auth.Scopes); scopeErr != nil {
			fmt.Fprintf(os.Stderr, "warning: could not save granted scopes for %s: %v\n", g.def.ID, scopeErr)
		}
	}

	// Verify connection + get account identifier
	account, err := g.runVerify(ctx, oauthCfg, token)
	if err != nil {
		// Non-fatal: connected but can't verify
		account = "connected (unverified)"
	}

	// Push encrypted refresh token to Convex for server-side reply detection
	if g.def.ID == "gmail" && token.RefreshToken != "" {
		if pushErr := PushGmailTokenToConvex(token, account); pushErr != nil {
			// Non-fatal: server-side features will be unavailable
			fmt.Fprintf(os.Stderr, "Warning: could not push token to server: %v\n", pushErr)
		}
	}

	return &Result{
		Account: account,
		Token:   token,
	}, nil
}

func (g *GenericConnector) connectAPIKey(ctx context.Context) (*Result, error) {
	key := os.Getenv(g.def.Auth.EnvVar)
	if key == "" {
		// Check if stdin is a TTY for prompt
		if fi, err := os.Stdin.Stat(); err == nil && fi.Mode()&os.ModeCharDevice != 0 {
			fmt.Printf("Enter your %s API key: ", g.def.Name)
			fmt.Scanln(&key)
		}
		if key == "" {
			return nil, fmt.Errorf("%s API key not found. Set %s environment variable", g.def.Name, g.def.Auth.EnvVar)
		}
	}

	// Validate that API key is non-empty (after trimming whitespace)
	key = strings.TrimSpace(key)
	if key == "" {
		return nil, fmt.Errorf("%s API key cannot be empty", g.def.Name)
	}

	// Save API key atomically with encryption (write encrypted to tmp, then rename)
	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
	if err := os.MkdirAll(tokenDir, 0700); err != nil {
		return nil, fmt.Errorf("creating connector dir: %w", err)
	}
	credsPath := tokenDir + "/credentials.json"
	credsData, _ := json.Marshal(map[string]string{"api_key": key})
	if err := writeEncryptedCredentials(credsPath, credsData); err != nil {
		return nil, fmt.Errorf("saving credentials: %w", err)
	}

	// Verify
	account, err := g.runVerifyAPIKey(ctx, key)
	if err != nil {
		account = "connected (unverified)"
	}

	return &Result{
		Account: account,
		Meta:    map[string]string{"api_key": key},
	}, nil
}

func (g *GenericConnector) connectBasic(ctx context.Context) (*Result, error) {
	username := os.Getenv(g.def.Auth.UsernameVar)
	password := os.Getenv(g.def.Auth.PasswordVar)

	// Validate that username and password are non-empty and not just whitespace
	if strings.TrimSpace(username) == "" || strings.TrimSpace(password) == "" {
		return nil, fmt.Errorf("%s credentials not found or empty. Set %s and %s environment variables with non-empty values",
			g.def.Name, g.def.Auth.UsernameVar, g.def.Auth.PasswordVar)
	}

	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
	if err := os.MkdirAll(tokenDir, 0700); err != nil {
		return nil, fmt.Errorf("creating connector dir: %w", err)
	}
	credsPath := tokenDir + "/credentials.json"
	credsData, _ := json.Marshal(map[string]string{"username": username, "password": password})
	if err := writeEncryptedCredentials(credsPath, credsData); err != nil {
		return nil, fmt.Errorf("saving credentials: %w", err)
	}

	return &Result{Account: username}, nil
}

func (g *GenericConnector) connectWebhook(ctx context.Context) (*Result, error) {
	webhookURL := os.Getenv(g.def.Auth.URLVar)
	if webhookURL == "" {
		if fi, err := os.Stdin.Stat(); err == nil && fi.Mode()&os.ModeCharDevice != 0 {
			fmt.Printf("Enter your %s webhook URL: ", g.def.Name)
			fmt.Scanln(&webhookURL)
		}
		if webhookURL == "" {
			return nil, fmt.Errorf("%s webhook URL not found. Set %s environment variable",
				g.def.Name, g.def.Auth.URLVar)
		}
	}

	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
	if err := os.MkdirAll(tokenDir, 0700); err != nil {
		return nil, fmt.Errorf("creating connector dir: %w", err)
	}
	credsPath := tokenDir + "/credentials.json"
	credsData, _ := json.Marshal(map[string]string{"webhook_url": webhookURL})
	if err := writeEncryptedCredentials(credsPath, credsData); err != nil {
		return nil, fmt.Errorf("saving credentials: %w", err)
	}

	return &Result{Account: webhookURL}, nil
}

// buildOAuthConfig creates a generic oauth2.Config from the YAML definition.
func (g *GenericConnector) buildOAuthConfig(clientID, clientSecret string) (*oauth2.Config, []oauth2.AuthCodeOption, error) {
	cfg := &oauth2.Config{
		ClientID:     clientID,
		ClientSecret: clientSecret,
		Scopes:       g.def.Auth.Scopes,
		Endpoint: oauth2.Endpoint{
			AuthURL:  g.def.Auth.AuthorizeURL,
			TokenURL: g.def.Auth.TokenURL,
		},
	}

	// Auth style
	switch g.def.Auth.AuthStyle {
	case "in_params":
		cfg.Endpoint.AuthStyle = oauth2.AuthStyleInParams
	case "in_header":
		cfg.Endpoint.AuthStyle = oauth2.AuthStyleInHeader
	}

	// Extra params become AuthCodeOptions
	var opts []oauth2.AuthCodeOption
	for k, v := range g.def.Auth.ExtraParams {
		opts = append(opts, oauth2.SetAuthURLParam(k, v))
	}

	return cfg, opts, nil
}

// resolveOAuthCredentials reads client ID and secret from the configured source.
func (g *GenericConnector) resolveOAuthCredentials() (string, string, error) {
	cred := g.def.Credentials

	switch cred.Source {
	case "env":
		id := os.Getenv(cred.ClientIDVar)
		secret := os.Getenv(cred.ClientSecretVar)
		if id == "" || secret == "" {
			return "", "", fmt.Errorf("%s credentials not configured.\n  Set %s and %s environment variables",
				g.def.Name, cred.ClientIDVar, cred.ClientSecretVar)
		}
		return id, secret, nil

	case "prompt":
		if fi, err := os.Stdin.Stat(); err != nil || fi.Mode()&os.ModeCharDevice == 0 {
			return "", "", fmt.Errorf("%s requires interactive input for credentials. Set environment variables or use a credentials file instead", g.def.Name)
		}
		var id, secret string
		fmt.Printf("Enter %s client ID: ", g.def.Name)
		fmt.Scanln(&id)
		fmt.Printf("Enter %s client secret: ", g.def.Name)
		fmt.Scanln(&secret)
		if id == "" || secret == "" {
			return "", "", fmt.Errorf("client ID and secret are required")
		}
		return id, secret, nil

	default:
		return "", "", fmt.Errorf("unsupported credential source %q for connector %s", cred.Source, g.def.ID)
	}
}

// loadGoogleCredentials loads credentials for google_json source (fallback chain).
func (g *GenericConnector) loadGoogleCredentials() ([]byte, error) {
	// 1. Explicit path from --credentials flag
	if g.credentials != "" {
		data, err := os.ReadFile(g.credentials)
		if err != nil {
			return nil, fmt.Errorf("reading credentials from %s: %w", g.credentials, err)
		}
		return data, nil
	}

	// 2. Local file in project
	localPath := fmt.Sprintf(".nurge/connectors/%s/credentials.json", g.def.ID)
	if data, err := os.ReadFile(localPath); err == nil {
		return data, nil
	}

	// 3. Bundled credentials
	if len(BundledCredentials) > 0 {
		return BundledCredentials, nil
	}

	return nil, fmt.Errorf("no %s credentials found -- provide a credentials.json file", g.def.Name)
}

package connector

import (
	"fmt"
	"os"
	"strings"
)

// LoadCredentials returns the raw credential bytes for a connector.
// For google_json connectors, returns the Google JSON file.
// For generic connectors, returns JSON with client_id and client_secret.
//
// Fallback chain: env override -> local file (encrypted or plaintext) -> bundled -> error
func LoadCredentials(connectorID string) ([]byte, error) {
	envPrefix := "NURGE_" + strings.ToUpper(strings.ReplaceAll(connectorID, "-", "_"))
	if raw := strings.TrimSpace(os.Getenv(envPrefix + "_CREDENTIALS_JSON")); raw != "" {
		return []byte(raw), nil
	}
	if path := strings.TrimSpace(os.Getenv(envPrefix + "_CREDENTIALS_FILE")); path != "" {
		data, err := os.ReadFile(path)
		if err != nil {
			return nil, fmt.Errorf("reading credentials file %q for connector %q: %w", path, connectorID, err)
		}
		return data, nil
	}

	// 1. Local file (may be encrypted)
	localPath := fmt.Sprintf(".nurge/connectors/%s/credentials.json", connectorID)
	if data, err := readEncryptedCredentials(localPath); err == nil {
		return data, nil
	}

	// 2. Bundled (only gmail has bundled creds)
	bundledPath := fmt.Sprintf("definitions/%s_credentials.json", connectorID)
	if data, err := bundledDefinitions.ReadFile(bundledPath); err == nil {
		return data, nil
	}

	return nil, fmt.Errorf("no credentials found for connector %q", connectorID)
}

