package connector

import (
	"crypto/aes"
	"crypto/cipher"
	"crypto/rand"
	"encoding/hex"
	"fmt"
	"os"

	"golang.org/x/oauth2"

	"github.com/usenurge/nurgesh/internal/account"
)

// PushGmailTokenToConvex encrypts the refresh token and sends it to Convex
// for server-side Gmail API access (reply detection without local machine).
func PushGmailTokenToConvex(token *oauth2.Token, email string) error {
	if token.RefreshToken == "" {
		return nil
	}

	encKey := os.Getenv("CONVEX_ENCRYPTION_KEY")
	if encKey == "" {
		fmt.Fprintf(os.Stderr, "warning: CONVEX_ENCRYPTION_KEY not set - server-side reply detection will be unavailable\n")
		return nil
	}

	convexURL := os.Getenv("NURGE_CONVEX_URL")
	if convexURL == "" {
		return nil // Convex URL not configured
	}

	auth, err := account.LoadAuth()
	if err != nil {
		return fmt.Errorf("loading auth for Convex push: %w", err)
	}

	encrypted, iv, err := encryptAESGCM(token.RefreshToken, encKey)
	if err != nil {
		return fmt.Errorf("encrypting token: %w", err)
	}

	client := account.NewConvexClient(convexURL)
	_, err = client.StoreGmailCredentials(auth.Token, email, encrypted, iv)
	return err
}

func encryptAESGCM(plaintext, keyHex string) (string, string, error) {
	key, err := hex.DecodeString(keyHex)
	if err != nil {
		return "", "", fmt.Errorf("invalid key hex: %w", err)
	}
	if len(key) != 32 {
		return "", "", fmt.Errorf("key must be 32 bytes (64 hex chars), got %d", len(key))
	}

	block, err := aes.NewCipher(key)
	if err != nil {
		return "", "", err
	}

	aesGCM, err := cipher.NewGCM(block)
	if err != nil {
		return "", "", err
	}

	nonce := make([]byte, aesGCM.NonceSize())
	if _, err := rand.Read(nonce); err != nil {
		return "", "", err
	}

	ciphertext := aesGCM.Seal(nil, nonce, []byte(plaintext), nil)
	return hex.EncodeToString(ciphertext), hex.EncodeToString(nonce), nil
}

