package connector

import (
	"fmt"
	"io/fs"
	"os"
	"path/filepath"
	"sort"
	"strings"
)

var builtinConnectorDefs = []ConnectorDef{
	{
		ID:       "linkedin",
		Name:     "LinkedIn",
		Type:     "social",
		Tier:     2,
		Required: false,
		Def: &YAMLConnector{
			SchemaVersion: 1,
			ID:            "linkedin",
			Name:          "LinkedIn",
			Type:          "social",
			Tier:          2,
			Required:      false,
			Description:   "LinkedIn via Nurge's server-managed Unipile connection flow",
			Auth: AuthConfig{
				Method: "oauth2",
			},
		},
	},
}

// IsBundled returns true if a connector with the given ID is shipped as a
// bundled YAML definition or hard-coded built-in. Bundled connectors cannot
// be removed via "connectors remove".
func IsBundled(id string) bool {
	// Check hard-coded built-ins first.
	for _, def := range builtinConnectorDefs {
		if def.ID == id {
			return true
		}
	}
	// Check embedded YAML definitions.
	_, err := bundledDefinitions.ReadFile("definitions/" + id + ".yaml")
	return err == nil
}

// LoadRegistry scans bundled definitions and project-local definitions,
// returning a merged list. Project-local definitions can override bundled
// Tier 2/3 connectors but NOT Tier 1 (email providers).
// projectDir is the path to .nurge/connectors/definitions/ (empty string to skip).
func LoadRegistry(projectDir string) ([]ConnectorDef, error) {
	defs := make(map[string]ConnectorDef)

	// 1. Load bundled definitions
	entries, err := fs.ReadDir(bundledDefinitions, "definitions")
	if err != nil {
		return nil, fmt.Errorf("reading bundled definitions: %w", err)
	}
	for _, entry := range entries {
		if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".yaml") {
			continue
		}
		data, err := bundledDefinitions.ReadFile("definitions/" + entry.Name())
		if err != nil {
			fmt.Fprintf(os.Stderr, "warning: could not read bundled definition %s: %v\n", entry.Name(), err)
			continue
		}
		yamlDef, err := ParseYAML(data)
		if err != nil {
			fmt.Fprintf(os.Stderr, "warning: invalid bundled connector definition %s: %v\n", entry.Name(), err)
			continue
		}
		if _, exists := defs[yamlDef.ID]; exists {
			fmt.Fprintf(os.Stderr, "warning: duplicate bundled connector definition %q, last one wins\n", yamlDef.ID)
		}
		defs[yamlDef.ID] = ConnectorDef{
			ID:       yamlDef.ID,
			Name:     yamlDef.Name,
			Type:     yamlDef.Type,
			Tier:     yamlDef.Tier,
			Required: yamlDef.Required,
			Def:      yamlDef,
		}
	}

	// 2. Add server-managed built-ins that don't have a YAML definition yet.
	for _, def := range builtinConnectorDefs {
		if _, exists := defs[def.ID]; !exists {
			defs[def.ID] = def
		}
	}

	// 3. Load project-local definitions (override Tier 2/3 only)
	if projectDir != "" {
		localEntries, err := os.ReadDir(projectDir)
		if err == nil { // silently skip if dir doesn't exist
			for _, entry := range localEntries {
				if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".yaml") {
					continue
				}

				// Validate that definition file names don't contain path traversal characters
				if strings.Contains(entry.Name(), "..") || strings.ContainsAny(entry.Name(), "/\\") {
					fmt.Fprintf(os.Stderr, "warning: skipping connector definition with suspicious filename: %s\n", entry.Name())
					continue
				}

				data, err := os.ReadFile(filepath.Join(projectDir, entry.Name()))
				if err != nil {
					fmt.Fprintf(os.Stderr, "warning: could not read project-local definition %s: %v\n", entry.Name(), err)
					continue
				}
				yamlDef, err := ParseYAML(data)
				if err != nil {
					fmt.Fprintf(os.Stderr, "warning: invalid project-local connector definition %s: %v\n", entry.Name(), err)
					continue
				}
				// Tier 1 connectors cannot be overridden
				if existing, ok := defs[yamlDef.ID]; ok && existing.Tier == 1 {
					fmt.Fprintf(os.Stderr, "warning: project-local definition for %q ignored (Tier 1 connectors cannot be overridden)\n", yamlDef.ID)
					continue
				}
				// Log warning when overriding a Tier 2/3 connector
				if existing, ok := defs[yamlDef.ID]; ok {
					fmt.Fprintf(os.Stderr, "warning: project-local definition for %q overrides bundled Tier %d connector\n", yamlDef.ID, existing.Tier)
				}
				defs[yamlDef.ID] = ConnectorDef{
					ID:       yamlDef.ID,
					Name:     yamlDef.Name,
					Type:     yamlDef.Type,
					Tier:     yamlDef.Tier,
					Required: yamlDef.Required,
					Def:      yamlDef,
				}
			}
		}
	}

	// Convert to sorted slice: email first (required), then crm, then enrichment
	typeOrder := map[string]int{
		"email":        0,
		"social":       1,
		"crm":          2,
		"enrichment":   3,
		"sequencing":   4,
		"notification": 5,
		"webhook":      6,
	}
	result := make([]ConnectorDef, 0, len(defs))
	for _, d := range defs {
		result = append(result, d)
	}
	sort.Slice(result, func(i, j int) bool {
		oi := typeOrder[result[i].Type]
		oj := typeOrder[result[j].Type]
		if oi != oj {
			return oi < oj
		}
		return result[i].Name < result[j].Name
	})

	return result, nil
}

