import { v } from "convex/values";
import { httpAction, internalQuery, internalMutation } from "./_generated/server";
import { api, internal } from "./_generated/api";
import { encryptToken, bytesToHex, hexToBytes } from "./crypto";
import { generateId } from "./helpers";

function jsonResponse(data: any, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { "Content-Type": "application/json" },
  });
}

async function authenticateRequest(ctx: any, request: Request) {
  const authHeader = request.headers.get("Authorization");
  if (!authHeader || !authHeader.startsWith("Bearer ")) {
    return { error: jsonResponse({ error: "Missing auth token" }, 401) };
  }
  const token = authHeader.slice(7);
  const user = await ctx.runQuery(internal.sendApi.findUserByToken, { token });
  if (!user) {
    return { error: jsonResponse({ error: "Invalid auth token" }, 401) };
  }
  return { user };
}

const SLACK_SCOPES = [
  "chat:write",
  "channels:read",
  "commands",
  "incoming-webhook",
];

const HUBSPOT_AUTHORIZE_URL = "https://app.hubspot.com/oauth/authorize";
const HUBSPOT_TOKEN_URL = "https://api.hubapi.com/oauth/v1/token";
const HUBSPOT_ACCESS_TOKEN_INFO_URL = "https://api.hubapi.com/oauth/v1/access-tokens";
const HUBSPOT_SCOPES = [
  "oauth",
  "crm.objects.contacts.read",
  "crm.objects.deals.read",
  "crm.objects.companies.read",
];
const OAUTH_CONNECT_STATE_TTL_MS = 15 * 60 * 1000;

function getSlackConfig() {
  const clientId =
    process.env.NURGE_SLACK_CLIENT_ID || process.env.SLACK_CLIENT_ID;
  const clientSecret =
    process.env.NURGE_SLACK_CLIENT_SECRET || process.env.SLACK_CLIENT_SECRET;
  const convexSiteUrl = process.env.CONVEX_SITE_URL;

  if (!clientId || !clientSecret) {
    throw new Error(
      "Slack credentials not configured. Set SLACK_CLIENT_ID and SLACK_CLIENT_SECRET."
    );
  }
  if (!convexSiteUrl) {
    throw new Error("CONVEX_SITE_URL not configured");
  }

  return { clientId, clientSecret, convexSiteUrl };
}

function getHubSpotConfig() {
  const clientId =
    process.env.HUBSPOT_CLIENT_ID || process.env.NURGE_HUBSPOT_CLIENT_ID;
  const clientSecret =
    process.env.HUBSPOT_CLIENT_SECRET || process.env.NURGE_HUBSPOT_CLIENT_SECRET;

  if (!clientId || !clientSecret) {
    throw new Error(
      "HubSpot credentials not configured. Set HUBSPOT_CLIENT_ID and HUBSPOT_CLIENT_SECRET."
    );
  }

  return { clientId, clientSecret };
}

function slackRedirectURL(convexSiteUrl: string) {
  return `${convexSiteUrl}/api/connect-slack-success`;
}

function hubSpotRedirectURL(origin: string) {
  return `${origin}/api/connect-hubspot-success`;
}

function htmlEscape(value: string) {
  return value
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#39;");
}

function renderConnectPage(title: string, message: string, status = 200) {
  const safeTitle = htmlEscape(title);
  const safeMessage = htmlEscape(message);
  const border = status >= 400 ? "#b42318" : "#16a34a";

package sequence

import (
	"database/sql"
	"fmt"
	"strings"
	"time"
)

func CreateEnrollmentAfterFirstTouch(d *sql.DB, opts EnrollmentOptions) (*Enrollment, *Task, error) {
	if opts.MailboxID == "" {
		return nil, nil, fmt.Errorf("mailbox ID is required")
	}
	if opts.ContactEmail == "" {
		return nil, nil, fmt.Errorf("contact email is required")
	}
	if opts.SentAt.IsZero() {
		opts.SentAt = time.Now()
	}
	template, err := TemplateByName(d, opts.SequenceName)
	if err != nil {
		return nil, nil, err
	}

	tx, err := d.Begin()
	if err != nil {
		return nil, nil, err
	}
	defer tx.Rollback()

	// Check inside transaction to prevent race condition where two concurrent
	// requests both pass the check before either inserts.
	var existingID string
	err = tx.QueryRow(`
		SELECT id FROM sequence_enrollments
		WHERE mailbox_id = ? AND lower(contact_email) = lower(?)
		AND status IN (?, ?)
		LIMIT 1`,
		opts.MailboxID, opts.ContactEmail, StatusActive, StatusPaused,
	).Scan(&existingID)
	if err == nil {
		return nil, nil, fmt.Errorf("%s already has an active sequence enrollment (%s)", opts.ContactEmail, existingID)
	}
	if err != sql.ErrNoRows {
		return nil, nil, fmt.Errorf("checking active enrollment: %w", err)
	}

	enrollmentID := newID("seq")
	nextDue := ""
	var nextTask *Task
	if len(template.Steps) > 1 {
		nextDelay, err := stepDelay(template.Steps[1])
		if err != nil {
			return nil, nil, err
		}
		nextDueAt := opts.SentAt.Add(nextDelay).UTC()
		nextSubject, nextBody := renderStep(template.Steps[1], Enrollment{
			SequenceName: template.Name,
			CampaignName: defaultCampaignName(opts),
			MailboxID:    opts.MailboxID,
			ContactEmail: opts.ContactEmail,
			ContactName:  opts.ContactName,
			Subject:      opts.Subject,
			ThreadID:     opts.ThreadID,
			InitialBody:  opts.InitialBody,
		})
		nextDue = nextDueAt.Format(time.RFC3339)
		nextTask = &Task{
			ID:           newID("task"),
			EnrollmentID: enrollmentID,
			MailboxID:    opts.MailboxID,
			ContactEmail: opts.ContactEmail,
			Subject:      nextSubject,
			Body:         nextBody,
			ThreadID:     opts.ThreadID,
			StepNumber:   template.Steps[1].StepNumber,
			StepName:     template.Steps[1].Name,
			SendType:     template.Steps[1].SendType,
			Status:       TaskStatusOpen,
			DueAt:        nextDueAt.Format(time.RFC3339),
			SequenceName: template.Name,
		}
	}

	_, err = tx.Exec(`
		INSERT INTO sequence_enrollments (
			id, sequence_name, campaign_name, mailbox_id, contact_email, contact_name, subject,
			thread_id, last_message_id, status, status_reason, reply_state, current_step, total_steps, last_sent_at, last_reply_at, next_due_at, initial_body
		) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
		enrollmentID, template.Name, defaultCampaignName(opts), opts.MailboxID, opts.ContactEmail, opts.ContactName,
		opts.Subject, opts.ThreadID, opts.MessageID, StatusActive, "", "", 1, len(template.Steps),
		opts.SentAt.UTC().Format(time.RFC3339), "", nextDue, opts.InitialBody,
	)
	if err != nil {
		return nil, nil, err
	}

	if nextTask != nil {
		_, err = tx.Exec(`
			INSERT INTO follow_up_tasks (
				id, enrollment_id, mailbox_id, contact_email, subject, body, thread_id,
				step_number, step_name, send_type, status, send_status, due_at
			) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
			nextTask.ID, nextTask.EnrollmentID, nextTask.MailboxID, nextTask.ContactEmail,
			nextTask.Subject, nextTask.Body, nextTask.ThreadID, nextTask.StepNumber, nextTask.StepName,
			nextTask.SendType, nextTask.Status, TaskSendStatusPending, nextTask.DueAt,
		)
		if err != nil {
			return nil, nil, err
		}
		if err := UpsertDraftForTask(tx, nextTask.ID, nextTask.EnrollmentID, nextTask.StepNumber, nextTask.Subject, nextTask.Body, "sequence-runtime", "initial enrollment"); err != nil {
			return nil, nil, err
		}
	}

	if err := tx.Commit(); err != nil {
		return nil, nil, err
	}

	enrollment, err := EnrollmentByID(d, enrollmentID)
	if err != nil {
		return nil, nil, err
	}

	if nextTask != nil {
		nextTask, err = TaskByID(d, nextTask.ID)
		if err != nil {
			return nil, nil, err
		}
	}

	return enrollment, nextTask, nil
}

func AdvanceTaskAfterSend(d *sql.DB, opts AdvanceOptions) (*Task, error) {
	if opts.TaskID == "" {
		return nil, fmt.Errorf("task ID is required")
	}
	if opts.SentAt.IsZero() {
		opts.SentAt = time.Now()
	}

	task, err := TaskByID(d, opts.TaskID)
	if err != nil {
		return nil, err
	}
	if task.Status != TaskStatusOpen {
		return nil, fmt.Errorf("task %s is %s", task.ID, task.Status)
	}

	enrollment, err := EnrollmentByID(d, task.EnrollmentID)
	if err != nil {
		return nil, err
	}

	template, err := TemplateByName(d, enrollment.SequenceName)
	if err != nil {
		return nil, err
	}

	tx, err := d.Begin()
	if err != nil {
		return nil, err
	}
	defer tx.Rollback()

	_, err = tx.Exec(`
		UPDATE follow_up_tasks
		SET status = ?, send_status = ?, completed_at = ?, updated_at = datetime('now')
		WHERE id = ?`,
		TaskStatusCompleted, TaskSendStatusSent, opts.SentAt.UTC().Format(time.RFC3339), task.ID,
	)
	if err != nil {
		return nil, err
	}
	if err := UpdateDraftStatusByTaskID(tx, task.ID, "sent"); err != nil {
		return nil, err
	}

	if task.StepNumber < 0 || task.StepNumber > len(template.Steps) {
		return nil, fmt.Errorf("step number %d is out of range for template %q (%d steps)", task.StepNumber, template.Name, len(template.Steps))
	}
	if task.StepNumber >= len(template.Steps) {
		_, err = tx.Exec(`
			UPDATE sequence_enrollments
			SET status = ?, current_step = ?, last_sent_at = ?, next_due_at = '',
				mailbox_id = CASE WHEN ? = '' THEN mailbox_id ELSE ? END,
				thread_id = CASE WHEN ? = '' THEN thread_id ELSE ? END,
				last_message_id = CASE WHEN ? = '' THEN last_message_id ELSE ? END,
				updated_at = datetime('now')
			WHERE id = ?`,
			StatusCompleted, task.StepNumber, opts.SentAt.UTC().Format(time.RFC3339),
			opts.MailboxID, opts.MailboxID,
			opts.ThreadID, opts.ThreadID, opts.MessageID, opts.MessageID, enrollment.ID,
		)
		if err != nil {
			return nil, err
		}

		if err := tx.Commit(); err != nil {
			return nil, err
		}
		return nil, nil
	}

	nextStep := template.Steps[task.StepNumber]
	nextDelay, err := stepDelay(nextStep)
	if err != nil {
		return nil, err
	}
	nextDueAt := opts.SentAt.Add(nextDelay).UTC()
	nextTaskID := newID("task")
	nextMailboxID := chooseString(opts.MailboxID, enrollment.MailboxID)
	nextThreadID := chooseString(opts.ThreadID, enrollment.ThreadID)
	renderEnrollment := *enrollment
	renderEnrollment.MailboxID = nextMailboxID
	renderEnrollment.ThreadID = nextThreadID
	renderEnrollment.LastMessageID = chooseString(opts.MessageID, enrollment.LastMessageID)
	nextSubject, nextBody := renderStep(nextStep, renderEnrollment)

	_, err = tx.Exec(`
		INSERT INTO follow_up_tasks (
			id, enrollment_id, mailbox_id, contact_email, subject, body, thread_id,
			step_number, step_name, send_type, status, send_status, due_at
		) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
		nextTaskID, enrollment.ID, nextMailboxID, enrollment.ContactEmail,
		nextSubject, nextBody, nextThreadID, nextStep.StepNumber,
		nextStep.Name, nextStep.SendType, TaskStatusOpen, TaskSendStatusPending, nextDueAt.Format(time.RFC3339),
	)
	if err != nil {
		return nil, err
	}
	if err := UpsertDraftForTask(tx, nextTaskID, enrollment.ID, nextStep.StepNumber, nextSubject, nextBody, "sequence-runtime", "advance task"); err != nil {
		return nil, err
	}

	_, err = tx.Exec(`
		UPDATE sequence_enrollments
		SET current_step = ?, last_sent_at = ?, next_due_at = ?,
			mailbox_id = CASE WHEN ? = '' THEN mailbox_id ELSE ? END,
			thread_id = CASE WHEN ? = '' THEN thread_id ELSE ? END,
			last_message_id = CASE WHEN ? = '' THEN last_message_id ELSE ? END,
			updated_at = datetime('now')
		WHERE id = ?`,
		task.StepNumber, opts.SentAt.UTC().Format(time.RFC3339), nextDueAt.Format(time.RFC3339),
		nextMailboxID, nextMailboxID,
		opts.ThreadID, opts.ThreadID, opts.MessageID, opts.MessageID, enrollment.ID,
	)
	if err != nil {
		return nil, err
	}

	if err := tx.Commit(); err != nil {
		return nil, err
	}

	return TaskByID(d, nextTaskID)
}

func EnrollmentByID(d *sql.DB, enrollmentID string) (*Enrollment, error) {
	row := d.QueryRow(`
		SELECT
			e.id, e.sequence_name, e.campaign_name, e.mailbox_id, m.email, e.contact_email,
			e.contact_name, e.subject, e.thread_id, e.last_message_id, e.status, e.status_reason,
			e.reply_state, e.current_step, e.total_steps, e.last_sent_at, e.last_reply_at, e.next_due_at, e.initial_body
		FROM sequence_enrollments e
		JOIN mailboxes m ON m.id = e.mailbox_id
		WHERE e.id = ?`,
		enrollmentID,
	)

	var e Enrollment
	if err := row.Scan(
		&e.ID, &e.SequenceName, &e.CampaignName, &e.MailboxID, &e.MailboxEmail, &e.ContactEmail,
		&e.ContactName, &e.Subject, &e.ThreadID, &e.LastMessageID, &e.Status, &e.StatusReason,
		&e.ReplyState, &e.CurrentStep, &e.TotalSteps, &e.LastSentAt, &e.LastReplyAt, &e.NextDueAt, &e.InitialBody,
	); err != nil {
		if err == sql.ErrNoRows {
			return nil, fmt.Errorf("sequence enrollment %q not found", enrollmentID)
		}
		return nil, err
	}
	return &e, nil
}

func ListEnrollments(d *sql.DB, status string, limit int) ([]Enrollment, error) {
	query := `
		SELECT
			e.id, e.sequence_name, e.campaign_name, e.mailbox_id, m.email, e.contact_email,
			e.contact_name, e.subject, e.thread_id, e.last_message_id, e.status, e.status_reason,
			e.reply_state, e.current_step, e.total_steps, e.last_sent_at, e.last_reply_at, e.next_due_at, e.initial_body
		FROM sequence_enrollments e
		JOIN mailboxes m ON m.id = e.mailbox_id`
	var args []any
	if status != "" {
		query += " WHERE e.status = ?"
		args = append(args, status)
	}
	query += " ORDER BY e.updated_at DESC"
	if limit > 0 {
		query += " LIMIT ?"
		args = append(args, limit)
	}

	rows, err := d.Query(query, args...)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var enrollments []Enrollment
	for rows.Next() {
		var e Enrollment
		if err := rows.Scan(
			&e.ID, &e.SequenceName, &e.CampaignName, &e.MailboxID, &e.MailboxEmail, &e.ContactEmail,
			&e.ContactName, &e.Subject, &e.ThreadID, &e.LastMessageID, &e.Status, &e.StatusReason,
			&e.ReplyState, &e.CurrentStep, &e.TotalSteps, &e.LastSentAt, &e.LastReplyAt, &e.NextDueAt, &e.InitialBody,
		); err != nil {
			return nil, err
		}
		enrollments = append(enrollments, e)
	}

	return enrollments, rows.Err()
}

func ActiveEnrollmentForContact(d *sql.DB, mailboxID, contactEmail string) (*Enrollment, error) {
	row := d.QueryRow(`
		SELECT id
		FROM sequence_enrollments
		WHERE mailbox_id = ? AND lower(contact_email) = lower(?) AND status IN (?, ?)
		ORDER BY updated_at DESC
		LIMIT 1`,
		mailboxID, strings.TrimSpace(contactEmail), StatusActive, StatusPaused,
	)

	var enrollmentID string
	if err := row.Scan(&enrollmentID); err != nil {
		if err == sql.ErrNoRows {
			return nil, nil
		}
		return nil, err
	}
	return EnrollmentByID(d, enrollmentID)
}

func PauseEnrollment(d *sql.DB, enrollmentID string) error {
	_, err := d.Exec(`
		UPDATE sequence_enrollments
		SET status = ?, updated_at = datetime('now')
		WHERE id = ? AND status != ?`,
		StatusPaused, enrollmentID, StatusCompleted,
	)
	return err
}

func ResumeEnrollment(d *sql.DB, enrollmentID string) error {
	_, err := d.Exec(`
		UPDATE sequence_enrollments
		SET status = ?, updated_at = datetime('now')
		WHERE id = ? AND status = ?`,
		StatusActive, enrollmentID, StatusPaused,
	)
	return err
}

func ListLeads(d *sql.DB, limit int, includeSuppressed bool) ([]Lead, error) {
	query := `
		SELECT
			c.email, MAX(c.name), MAX(c.domain), MAX(c.company), MAX(c.title), MAX(c.owner),
			MAX(c.lead_status), MAX(COALESCE(c.last_activity_at, '')), MAX(c.email_count),
			COALESCE(se.status, ''), COALESCE(se.sequence_name, ''), COALESCE(se.campaign_name, ''),
			CASE WHEN se_sup.id IS NOT NULL OR sd_sup.id IS NOT NULL THEN 1 ELSE 0 END,
			COALESCE(se_sup.reason, sd_sup.reason, '')
		FROM contacts c
		LEFT JOIN sequence_enrollments se
			ON se.id = (
				SELECT id FROM sequence_enrollments
				WHERE contact_email = c.email
				ORDER BY updated_at DESC
					LIMIT 1
				)
		LEFT JOIN suppressions se_sup
			ON se_sup.scope = 'email' AND se_sup.value = lower(c.email)
		LEFT JOIN suppressions sd_sup
			ON sd_sup.scope = 'domain' AND sd_sup.value = lower(c.domain)
		GROUP BY c.email, se.status, se.sequence_name, se.campaign_name, se_sup.id, se_sup.reason, sd_sup.id, sd_sup.reason
		ORDER BY MAX(COALESCE(c.last_activity_at, '')) DESC, c.email ASC`
	var queryArgs []any
	if limit > 0 {
		query += " LIMIT ?"
		queryArgs = append(queryArgs, limit)
	}

	rows, err := d.Query(query, queryArgs...)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var leads []Lead
	for rows.Next() {
		var lead Lead
		var suppressed int
		if err := rows.Scan(
			&lead.Email, &lead.Name, &lead.Domain, &lead.Company, &lead.Title, &lead.Owner,
			&lead.LeadStatus, &lead.LastActivityAt, &lead.EmailCount,
			&lead.EnrollmentStatus, &lead.SequenceName, &lead.CampaignName,
			&suppressed, &lead.SuppressionReason,
		); err != nil {
			return nil, err
		}
		lead.Suppressed = suppressed == 1
		if !includeSuppressed && lead.Suppressed {
			continue
		}
		leads = append(leads, lead)
	}

	return leads, rows.Err()
}

package sequence

import (
	"database/sql"
	"fmt"
	"strings"
	"time"
)

type execer interface {
	Exec(query string, args ...any) (sql.Result, error)
}

const (
	TaskSendStatusPending = "pending"
	TaskSendStatusSent    = "sent"
	TaskSendStatusFailed  = "failed"
)

type SendAttempt struct {
	ID           string `json:"id"`
	MailboxID    string `json:"mailbox_id"`
	MailboxEmail string `json:"mailbox_email"`
	EnrollmentID string `json:"enrollment_id"`
	TaskID       string `json:"task_id"`
	ContactEmail string `json:"contact_email"`
	SendType     string `json:"send_type"`
	Status       string `json:"status"`
	Subject      string `json:"subject"`
	Error        string `json:"error"`
	MessageID    string `json:"message_id"`
	ProviderID   string `json:"provider_id"`
	AttemptedAt  string `json:"attempted_at"`
}

type SequenceDraft struct {
	ID               string `json:"id"`
	EnrollmentID     string `json:"enrollment_id"`
	TaskID           string `json:"task_id"`
	StepNumber       int    `json:"step_number"`
	Subject          string `json:"subject"`
	Body             string `json:"body"`
	Channel          string `json:"channel"`
	Status           string `json:"status"`
	GeneratedBy      string `json:"generated_by"`
	GeneratedContext string `json:"generated_context"`
}

type SendAttemptOptions struct {
	MailboxID    string
	EnrollmentID string
	TaskID       string
	ContactEmail string
	SendType     string
	Status       string
	Subject      string
	Error        string
	MessageID    string
	ProviderID   string
	AttemptedAt  time.Time
}

func RecordSend(d *sql.DB, mailboxID, sendType string, now time.Time) error {
	normalized := NormalizeSendType(sendType)
	// If the original type was not a recognized value and fell back to "manual", reject it.
	if normalized == SendTypeManual && sendType != SendTypeManual {
		return fmt.Errorf("unknown send type %q: expected one of first_touch, follow_up, reply, manual", sendType)
	}
	if normalized == SendTypeManual {
		return nil
	}
	sendType = normalized
	if now.IsZero() {
		now = time.Now()
	}

	tx, err := d.Begin()
	if err != nil {
		return fmt.Errorf("beginning transaction: %w", err)
	}
	defer tx.Rollback()

	if _, err := tx.Exec(`
		INSERT INTO mailbox_daily_usage (
			mailbox_id, usage_day, first_touches_sent, follow_ups_sent, replies_sent
		) VALUES (?, ?, 0, 0, 0)
		ON CONFLICT(mailbox_id, usage_day) DO NOTHING`,
		mailboxID, dayKey(now),
	); err != nil {
		return err
	}

	column := usageColumn(sendType)
	// Validate the column name is one of the known safe values before interpolation
	switch column {
	case "first_touches_sent", "follow_ups_sent", "replies_sent":
		if err := validateIdentifier(column); err != nil {
			return fmt.Errorf("unsafe column name %q: %w", column, err)
		}
		if _, err := tx.Exec(
			fmt.Sprintf(`UPDATE mailbox_daily_usage SET %s = %s + 1 WHERE mailbox_id = ? AND usage_day = ?`, column, column),
			mailboxID, dayKey(now),
		); err != nil {
			return err
		}
	case "":
		// No usage column for this send type (e.g. manual)
	default:
		return fmt.Errorf("unexpected usage column %q for send type %q", column, sendType)
	}

	if _, err := tx.Exec(`
		INSERT INTO mailbox_send_events (id, mailbox_id, send_type, sent_at)
		VALUES (?, ?, ?, ?)`,
		newID("mse"), mailboxID, sendType, now.UTC().Format(time.RFC3339),
	); err != nil {
		return err
	}

	if _, err := tx.Exec(`UPDATE mailboxes SET last_used_at = ?, updated_at = datetime('now') WHERE id = ?`,
		now.UTC().Format(time.RFC3339), mailboxID,
	); err != nil {
		return err
	}

	return tx.Commit()
}

func LogSendAttempt(d *sql.DB, opts SendAttemptOptions) error {
	if opts.MailboxID == "" {
		return fmt.Errorf("mailbox ID is required")
	}
	if strings.TrimSpace(opts.ContactEmail) == "" {
		return fmt.Errorf("contact email is required")
	}
	if strings.TrimSpace(opts.Status) == "" {
		return fmt.Errorf("send attempt status is required")
	}
	if opts.AttemptedAt.IsZero() {
		opts.AttemptedAt = time.Now()
	}

	_, err := d.Exec(`
		INSERT INTO send_attempts (
			id, mailbox_id, enrollment_id, task_id, contact_email, send_type,
			status, subject, error, message_id, provider_id, attempted_at
		) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
		newID("send"), opts.MailboxID, opts.EnrollmentID, opts.TaskID, strings.ToLower(strings.TrimSpace(opts.ContactEmail)),
		NormalizeSendType(opts.SendType), opts.Status, opts.Subject, opts.Error, opts.MessageID, opts.ProviderID,
		opts.AttemptedAt.UTC().Format(time.RFC3339),
	)
	return err
}

func ListSendAttempts(d *sql.DB, limit int, status string) ([]SendAttempt, error) {
	query := `
		SELECT s.id, s.mailbox_id, m.email, s.enrollment_id, s.task_id, s.contact_email, s.send_type,
			s.status, s.subject, s.error, s.message_id, s.provider_id, s.attempted_at
		FROM send_attempts s
		JOIN mailboxes m ON m.id = s.mailbox_id`
	var args []any
	if status != "" {
		query += ` WHERE s.status = ?`
		args = append(args, status)
	}
	query += ` ORDER BY s.attempted_at DESC`
	if limit > 0 {
		query += " LIMIT ?"
		args = append(args, limit)
	}

	rows, err := d.Query(query, args...)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var attempts []SendAttempt
	for rows.Next() {
		var item SendAttempt
		if err := rows.Scan(
			&item.ID, &item.MailboxID, &item.MailboxEmail, &item.EnrollmentID, &item.TaskID, &item.ContactEmail,
			&item.SendType, &item.Status, &item.Subject, &item.Error, &item.MessageID, &item.ProviderID, &item.AttemptedAt,
		); err != nil {
			return nil, err
		}
		attempts = append(attempts, item)
	}
	return attempts, rows.Err()
}

func UpdateTaskSendState(d *sql.DB, taskID, sendStatus, messageID, providerID, lastError string) error {
	sendStatus = strings.TrimSpace(sendStatus)
	if sendStatus == "" {
		sendStatus = TaskSendStatusPending
	}
	_, err := d.Exec(`
		UPDATE follow_up_tasks
		SET send_status = ?,
			unipile_message_id = CASE WHEN ? = '' THEN unipile_message_id ELSE ? END,
			provider_id = CASE WHEN ? = '' THEN provider_id ELSE ? END,
			last_error = CASE WHEN ? = '' THEN last_error ELSE ? END,
			updated_at = datetime('now')
		WHERE id = ?`,
		sendStatus,
		messageID, messageID,
		providerID, providerID,
		lastError, lastError,
		taskID,
	)
	return err
}

func UpsertDraftForTask(d execer, taskID, enrollmentID string, stepNumber int, subject, body, generatedBy, generatedContext string) error {
	if taskID == "" || enrollmentID == "" {
		return fmt.Errorf("task ID and enrollment ID are required")
	}
	_, err := d.Exec(`
		INSERT INTO sequence_drafts (
			id, enrollment_id, task_id, step_number, subject, body, channel, status, generated_by, generated_context
		) VALUES (?, ?, ?, ?, ?, ?, 'email', 'pending', ?, ?)
		ON CONFLICT(task_id) DO UPDATE SET
			subject = excluded.subject,
			body = excluded.body,
			generated_by = excluded.generated_by,
			generated_context = excluded.generated_context,
			status = CASE
				WHEN sequence_drafts.status = 'sent' THEN sequence_drafts.status
				ELSE excluded.status
			END,
			updated_at = datetime('now')`,
		newID("draft"), enrollmentID, taskID, stepNumber, subject, body, generatedBy, generatedContext,
	)
	return err
}

func DraftByTaskID(d *sql.DB, taskID string) (*SequenceDraft, error) {
	row := d.QueryRow(`
		SELECT id, enrollment_id, task_id, step_number, subject, body, channel, status, generated_by, generated_context
		FROM sequence_drafts
		WHERE task_id = ?`,
		taskID,
	)
	var draft SequenceDraft
	if err := row.Scan(
		&draft.ID, &draft.EnrollmentID, &draft.TaskID, &draft.StepNumber, &draft.Subject, &draft.Body,
		&draft.Channel, &draft.Status, &draft.GeneratedBy, &draft.GeneratedContext,
	); err != nil {
		if err == sql.ErrNoRows {
			return nil, fmt.Errorf("draft for task %q not found", taskID)
		}
		return nil, err
	}
	return &draft, nil
}

func UpdateDraftStatusByTaskID(d execer, taskID, status string) error {
	_, err := d.Exec(`UPDATE sequence_drafts SET status = ?, updated_at = datetime('now') WHERE task_id = ?`, status, taskID)
	return err
}

