   364→	if err != nil {
   365→		return 0, err
   366→	}
   367→	firstTouchCap, followUpCap, replyCap := effectiveCaps(*mailbox, now)
   368→	switch NormalizeSendType(sendType) {
   369→	case SendTypeFirstTouch:
   370→		return remaining(firstTouchCap, usage.FirstTouchesSent), nil
   371→	case SendTypeFollowUp:
   372→		return remaining(followUpCap, usage.FollowUpsSent), nil
   373→	case SendTypeReply:
   374→		return remaining(replyCap, usage.RepliesSent), nil
   375→	default:
   376→		return -1, nil
   377→	}
   378→}
   379→
   380→func latestMailboxOutboundAt(d *sql.DB, mailboxEmail string) (time.Time, error) {
   381→	row := d.QueryRow(`
   382→		SELECT date
   383→		FROM emails
   384→		WHERE lower(from_email) = lower(?) AND direction = 'outbound'
   385→		ORDER BY date DESC
   386→		LIMIT 1`,
   387→		mailboxEmail,
   388→	)
   389→
   390→	var value string
   391→	if err := row.Scan(&value); err != nil {
   392→		if err == sql.ErrNoRows {
   393→			return time.Time{}, nil
   394→		}
   395→		return time.Time{}, err
   396→	}
   397→
   398→	for _, layout := range []string{
   399→		time.RFC3339,
   400→		time.RFC1123Z,
   401→		"Mon, 2 Jan 2006 15:04:05 -0700",
   402→		"2006-01-02 15:04:05",
   403→		"2006-01-02",
   404→	} {
   405→		if ts, err := time.Parse(layout, value); err == nil {
   406→			return ts.UTC(), nil
   407→		}
   408→	}
   409→	return time.Time{}, nil
   410→}
