   412→func ResolveTaskMailbox(d *sql.DB, task Task, transportEmail string, now time.Time) (*Mailbox, error) {
   413→	if now.IsZero() {
   414→		now = time.Now()
   415→	}
   416→
   417→	primary, err := mailboxByID(d, task.MailboxID)
   418→	if err != nil {
