   438→
   439→func rotationCandidates(d *sql.DB, primary Mailbox, sendType, transportEmail string, now time.Time) ([]*Mailbox, error) {
   440→	rows, err := d.Query(`
   441→		SELECT id, email, transport_email, rotation_group, provider, status, warmup_stage, warmup_started_at,
   442→			first_touch_daily_cap, follow_up_daily_cap, reply_daily_cap, min_gap_minutes,
   443→			send_window_start_hour, send_window_end_hour, send_window_timezone,
   444→			reputation_score, priority, last_used_at, last_bounce_at,
   445→			COALESCE(u.first_touches_sent, 0), COALESCE(u.follow_ups_sent, 0), COALESCE(u.replies_sent, 0)
   446→		FROM mailboxes
   447→		LEFT JOIN mailbox_daily_usage u
   448→			ON u.mailbox_id = mailboxes.id AND u.usage_day = ?
   449→		WHERE provider = ? AND rotation_group = ?
   450→		ORDER BY email ASC`,
   451→		dayKey(now), primary.Provider, primary.RotationGroup,
   452→	)
   453→	if err != nil {
   454→		return nil, err
   455→	}
   456→	defer rows.Close()
   457→
   458→	type candidate struct {
   459→		mailbox          *Mailbox
   460→		firstTouchesSent int
   461→		followUpsSent    int
   462→		repliesSent      int
   463→		remaining        int
   464→	}
   465→
   466→	var rawCandidates []candidate
   467→	blocked := map[string]string{}
   468→	for rows.Next() {
   469→		var item Mailbox
   470→		var firstTouchesSent, followUpsSent, repliesSent int
   471→		if err := rows.Scan(
   472→			&item.ID, &item.Email, &item.TransportEmail, &item.RotationGroup, &item.Provider, &item.Status, &item.WarmupStage, &item.WarmupStartedAt,
   473→			&item.FirstTouchDailyCap, &item.FollowUpDailyCap, &item.ReplyDailyCap, &item.MinGapMinutes,
   474→			&item.SendWindowStartHour, &item.SendWindowEndHour, &item.SendWindowTimezone,
   475→			&item.ReputationScore, &item.Priority, &item.LastUsedAt, &item.LastBounceAt,
   476→			&firstTouchesSent, &followUpsSent, &repliesSent,
   477→		); err != nil {
   478→			return nil, err
   479→		}
   480→		if !strings.EqualFold(effectiveTransportEmail(item), transportEmail) {
   481→			continue
   482→		}
   483→		rawCandidates = append(rawCandidates, candidate{
   484→			mailbox:          &item,
   485→			firstTouchesSent: firstTouchesSent,
   486→			followUpsSent:    followUpsSent,
   487→			repliesSent:      repliesSent,
   488→		})
   489→	}
   490→	if err := rows.Err(); err != nil {
   491→		return nil, err
   492→	}
   493→	if err := rows.Close(); err != nil {
   494→		return nil, err
   495→	}
   496→
   497→	candidates := make([]candidate, 0, len(rawCandidates))
   498→	for _, item := range rawCandidates {
   499→		if err := CanSend(d, item.mailbox.ID, sendType, now); err != nil {
   500→			blocked[item.mailbox.ID] = err.Error()
   501→			continue
   502→		}
   503→
   504→		firstTouchCap, followUpCap, replyCap := effectiveCaps(*item.mailbox, now)
   505→		switch NormalizeSendType(sendType) {
   506→		case SendTypeFirstTouch:
   507→			item.remaining = remaining(firstTouchCap, item.firstTouchesSent)
   508→		case SendTypeFollowUp:
   509→			item.remaining = remaining(followUpCap, item.followUpsSent)
   510→		case SendTypeReply:
   511→			item.remaining = remaining(replyCap, item.repliesSent)
   512→		default:
   513→			item.remaining = -1
   514→		}
   515→		candidates = append(candidates, item)
   516→	}
   517→
   518→	sort.SliceStable(candidates, func(i, j int) bool {
   519→		left := candidates[i]
   520→		right := candidates[j]
   521→		if left.mailbox.ID == primary.ID && right.mailbox.ID != primary.ID {
   522→			return true
   523→		}
   524→		if right.mailbox.ID == primary.ID && left.mailbox.ID != primary.ID {
   525→			return false
   526→		}
   527→		if left.mailbox.Priority != right.mailbox.Priority {
   528→			return left.mailbox.Priority > right.mailbox.Priority
   529→		}
   530→		if left.mailbox.ReputationScore != right.mailbox.ReputationScore {
   531→			return left.mailbox.ReputationScore > right.mailbox.ReputationScore
   532→		}
   533→		if left.remaining != right.remaining {
   534→			return left.remaining > right.remaining
   535→		}
   536→		leftUsed := parseOptionalTime(left.mailbox.LastUsedAt)
   537→		rightUsed := parseOptionalTime(right.mailbox.LastUsedAt)
   538→		if leftUsed.IsZero() != rightUsed.IsZero() {
   539→			return leftUsed.IsZero()
   540→		}
   541→		if !leftUsed.Equal(rightUsed) {
   542→			return leftUsed.Before(rightUsed)
   543→		}
   544→		return left.mailbox.Email < right.mailbox.Email
   545→	})
   546→
   547→	if len(candidates) == 0 {
   548→		if reason := blocked[primary.ID]; reason != "" {
   549→			return nil, fmt.Errorf("%s", reason)
   550→		}
   551→	}
   552→
   553→	result := make([]*Mailbox, 0, len(candidates))
   554→	for _, item := range candidates {
   555→		result = append(result, item.mailbox)
   556→	}
   557→	return result, nil
   558→}
   559→
   560→func withinSendWindow(mailbox Mailbox, now time.Time) bool {
   561→	start := clampHour(mailbox.SendWindowStartHour)
   562→	end := clampHour(mailbox.SendWindowEndHour)
   563→	if start == end {
   564→		return true
   565→	}
   566→
   567→	loc := time.Local
   568→	tz := strings.TrimSpace(mailbox.SendWindowTimezone)
   569→	if tz != "" && !strings.EqualFold(tz, "local") {
   570→		if loaded, err := time.LoadLocation(tz); err == nil {
   571→			loc = loaded
   572→		}
   573→	}
   574→	hour := now.In(loc).Hour()
   575→	if start < end {
   576→		return hour >= start && hour < end
   577→	}
   578→	return hour >= start || hour < end
   579→}
   580→
   581→func effectiveTransportEmail(mailbox Mailbox) string {
   582→	if strings.TrimSpace(mailbox.TransportEmail) != "" {
   583→		return strings.TrimSpace(mailbox.TransportEmail)
   584→	}
   585→	return strings.TrimSpace(mailbox.Email)
   586→}
   587→
   588→func effectiveCaps(mailbox Mailbox, now time.Time) (int, int, int) {
   589→	if now.IsZero() {
   590→		now = time.Now()
   591→	}
   592→	firstTouchCap := mailbox.FirstTouchDailyCap
   593→	followUpCap := mailbox.FollowUpDailyCap
   594→	replyCap := mailbox.ReplyDailyCap
   595→
   596→	switch strings.ToLower(strings.TrimSpace(mailbox.WarmupStage)) {
   597→	case "warming":
   598→		day := warmupDay(mailbox, now)
   599→		firstTouchCap = minPositive(firstTouchCap, 3+day*2)
   600→		followUpCap = minPositive(followUpCap, 6+day*4)
   601→	case "ramping":
   602→		day := warmupDay(mailbox, now)
   603→		firstTouchCap = minPositive(firstTouchCap, 5+day*5)
   604→		followUpCap = minPositive(followUpCap, 10+day*10)
   605→	}
   606→
   607→	switch {
   608→	case mailbox.ReputationScore > 0 && mailbox.ReputationScore < 70:
   609→		firstTouchCap = scaledCap(firstTouchCap, 0.5)
   610→		followUpCap = scaledCap(followUpCap, 0.75)
   611→	case mailbox.ReputationScore > 0 && mailbox.ReputationScore < 85:
   612→		firstTouchCap = scaledCap(firstTouchCap, 0.75)
   613→	}
   614→
   615→	return firstTouchCap, followUpCap, replyCap
   616→}
