func mailboxRemainingCapacity(d *sql.DB, mailboxID, sendType string, now time.Time) (int, error) {
	mailbox, usage, err := mailboxAndUsage(d, mailboxID, now)
	if err != nil {
		return 0, err
	}
	firstTouchCap, followUpCap, replyCap := effectiveCaps(*mailbox, now)
	switch NormalizeSendType(sendType) {
	case SendTypeFirstTouch:
		return remaining(firstTouchCap, usage.FirstTouchesSent), nil
	case SendTypeFollowUp:
		return remaining(followUpCap, usage.FollowUpsSent), nil
	case SendTypeReply:
		return remaining(replyCap, usage.RepliesSent), nil
	default:
		return -1, nil
	}
}

func latestMailboxOutboundAt(d *sql.DB, mailboxEmail string) (time.Time, error) {
	row := d.QueryRow(`
		SELECT date
		FROM emails
		WHERE lower(from_email) = lower(?) AND direction = 'outbound'
		ORDER BY date DESC
		LIMIT 1`,
		mailboxEmail,
	)

	var value string
	if err := row.Scan(&value); err != nil {
		if err == sql.ErrNoRows {
			return time.Time{}, nil
		}
		return time.Time{}, err
	}

	for _, layout := range []string{
		time.RFC3339,
		time.RFC1123Z,
		"Mon, 2 Jan 2006 15:04:05 -0700",
		"2006-01-02 15:04:05",
		"2006-01-02",
	} {
		if ts, err := time.Parse(layout, value); err == nil {
			return ts.UTC(), nil
		}
	}
	return time.Time{}, nil
}

func ResolveTaskMailbox(d *sql.DB, task Task, transportEmail string, now time.Time) (*Mailbox, error) {
	if now.IsZero() {
		now = time.Now()
	}

	primary, err := mailboxByID(d, task.MailboxID)
	if err != nil {
		return nil, err
	}

	if transportEmail == "" {
		if err := CanSend(d, primary.ID, task.SendType, now); err != nil {
			return nil, err
		}
		return primary, nil
	}

	candidates, err := rotationCandidates(d, *primary, task.SendType, transportEmail, now)
	if err != nil {
		return nil, err
	}
	if len(candidates) == 0 {
		return nil, fmt.Errorf("no mailbox in rotation group %q is ready for transport %s", primary.RotationGroup, transportEmail)
	}
	return candidates[0], nil
}

func rotationCandidates(d *sql.DB, primary Mailbox, sendType, transportEmail string, now time.Time) ([]*Mailbox, error) {
	rows, err := d.Query(`
		SELECT id, email, transport_email, rotation_group, provider, status, warmup_stage, warmup_started_at,
			first_touch_daily_cap, follow_up_daily_cap, reply_daily_cap, min_gap_minutes,
			send_window_start_hour, send_window_end_hour, send_window_timezone,
			reputation_score, priority, last_used_at, last_bounce_at,
			COALESCE(u.first_touches_sent, 0), COALESCE(u.follow_ups_sent, 0), COALESCE(u.replies_sent, 0)
		FROM mailboxes
		LEFT JOIN mailbox_daily_usage u
			ON u.mailbox_id = mailboxes.id AND u.usage_day = ?
		WHERE provider = ? AND rotation_group = ?
		ORDER BY email ASC`,
		dayKey(now), primary.Provider, primary.RotationGroup,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	type candidate struct {
		mailbox          *Mailbox
		firstTouchesSent int
		followUpsSent    int
		repliesSent      int
		remaining        int
	}

	var rawCandidates []candidate
	blocked := map[string]string{}
	for rows.Next() {
		var item Mailbox
		var firstTouchesSent, followUpsSent, repliesSent int
		if err := rows.Scan(
			&item.ID, &item.Email, &item.TransportEmail, &item.RotationGroup, &item.Provider, &item.Status, &item.WarmupStage, &item.WarmupStartedAt,
			&item.FirstTouchDailyCap, &item.FollowUpDailyCap, &item.ReplyDailyCap, &item.MinGapMinutes,
			&item.SendWindowStartHour, &item.SendWindowEndHour, &item.SendWindowTimezone,
			&item.ReputationScore, &item.Priority, &item.LastUsedAt, &item.LastBounceAt,
			&firstTouchesSent, &followUpsSent, &repliesSent,
		); err != nil {
			return nil, err
		}
		if !strings.EqualFold(effectiveTransportEmail(item), transportEmail) {
			continue
		}
		rawCandidates = append(rawCandidates, candidate{
			mailbox:          &item,
			firstTouchesSent: firstTouchesSent,
			followUpsSent:    followUpsSent,
			repliesSent:      repliesSent,
		})
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}

	candidates := make([]candidate, 0, len(rawCandidates))
	for _, item := range rawCandidates {
		if err := CanSend(d, item.mailbox.ID, sendType, now); err != nil {
			blocked[item.mailbox.ID] = err.Error()
			continue
		}

		firstTouchCap, followUpCap, replyCap := effectiveCaps(*item.mailbox, now)
		switch NormalizeSendType(sendType) {
		case SendTypeFirstTouch:
			item.remaining = remaining(firstTouchCap, item.firstTouchesSent)
		case SendTypeFollowUp:
			item.remaining = remaining(followUpCap, item.followUpsSent)
		case SendTypeReply:
			item.remaining = remaining(replyCap, item.repliesSent)
		default:
			item.remaining = -1
		}
		candidates = append(candidates, item)
	}

	sort.SliceStable(candidates, func(i, j int) bool {
		left := candidates[i]
		right := candidates[j]
		if left.mailbox.ID == primary.ID && right.mailbox.ID != primary.ID {
			return true
		}
		if right.mailbox.ID == primary.ID && left.mailbox.ID != primary.ID {
			return false
		}
		if left.mailbox.Priority != right.mailbox.Priority {
			return left.mailbox.Priority > right.mailbox.Priority
		}
		if left.mailbox.ReputationScore != right.mailbox.ReputationScore {
			return left.mailbox.ReputationScore > right.mailbox.ReputationScore
		}
		if left.remaining != right.remaining {
			return left.remaining > right.remaining
		}
		leftUsed := parseOptionalTime(left.mailbox.LastUsedAt)
		rightUsed := parseOptionalTime(right.mailbox.LastUsedAt)
		if leftUsed.IsZero() != rightUsed.IsZero() {
			return leftUsed.IsZero()
		}
		if !leftUsed.Equal(rightUsed) {
			return leftUsed.Before(rightUsed)
		}
		return left.mailbox.Email < right.mailbox.Email
	})

	if len(candidates) == 0 {
		if reason := blocked[primary.ID]; reason != "" {
			return nil, fmt.Errorf("%s", reason)
		}
	}

	result := make([]*Mailbox, 0, len(candidates))
	for _, item := range candidates {
		result = append(result, item.mailbox)
	}
	return result, nil
}

func withinSendWindow(mailbox Mailbox, now time.Time) bool {
	start := clampHour(mailbox.SendWindowStartHour)
	end := clampHour(mailbox.SendWindowEndHour)
	if start == end {
		return true
	}

	loc := time.Local
	tz := strings.TrimSpace(mailbox.SendWindowTimezone)
	if tz != "" && !strings.EqualFold(tz, "local") {
		if loaded, err := time.LoadLocation(tz); err == nil {
			loc = loaded
		}
	}
	hour := now.In(loc).Hour()
	if start < end {
		return hour >= start && hour < end
	}
	return hour >= start || hour < end
}

func effectiveTransportEmail(mailbox Mailbox) string {
	if strings.TrimSpace(mailbox.TransportEmail) != "" {
		return strings.TrimSpace(mailbox.TransportEmail)
	}
	return strings.TrimSpace(mailbox.Email)
}

func effectiveCaps(mailbox Mailbox, now time.Time) (int, int, int) {
	if now.IsZero() {
		now = time.Now()
	}
	firstTouchCap := mailbox.FirstTouchDailyCap
	followUpCap := mailbox.FollowUpDailyCap
	replyCap := mailbox.ReplyDailyCap

	switch strings.ToLower(strings.TrimSpace(mailbox.WarmupStage)) {
	case "warming":
		day := warmupDay(mailbox, now)
		firstTouchCap = minPositive(firstTouchCap, 3+day*2)
		followUpCap = minPositive(followUpCap, 6+day*4)
	case "ramping":
		day := warmupDay(mailbox, now)
		firstTouchCap = minPositive(firstTouchCap, 5+day*5)
		followUpCap = minPositive(followUpCap, 10+day*10)
	}

	switch {
	case mailbox.ReputationScore > 0 && mailbox.ReputationScore < 70:
		firstTouchCap = scaledCap(firstTouchCap, 0.5)
		followUpCap = scaledCap(followUpCap, 0.75)
	case mailbox.ReputationScore > 0 && mailbox.ReputationScore < 85:
		firstTouchCap = scaledCap(firstTouchCap, 0.75)
	}

	return firstTouchCap, followUpCap, replyCap
}

package sequence

import (
	"database/sql"
	"fmt"
	"strings"
	"time"
)

func ListReplyQueue(d *sql.DB, limit int) ([]ReplyEvent, error) {
	query := `
		SELECT id, enrollment_id, mailbox_id, thread_id, message_id, contact_email, classification,
			status, assigned_to, subject, snippet, draft_reply, handled_at, occurred_at
		FROM reply_events
		WHERE status = 'open'
		ORDER BY occurred_at ASC, id ASC`
	var args []any
	if limit > 0 {
		query += " LIMIT ?"
		args = append(args, limit)
	}

	rows, err := d.Query(query, args...)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var items []ReplyEvent
	for rows.Next() {
		var item ReplyEvent
		if err := rows.Scan(
			&item.ID, &item.EnrollmentID, &item.MailboxID, &item.ThreadID, &item.MessageID, &item.ContactEmail,
			&item.Classification, &item.Status, &item.AssignedTo, &item.Subject, &item.Snippet, &item.DraftReply,
			&item.HandledAt, &item.OccurredAt,
		); err != nil {
			return nil, err
		}
		item.NeedsAction = item.Status == "open"
		items = append(items, item)
	}
	return items, rows.Err()
}

func MarkReplyHandled(d *sql.DB, replyID, assignedTo string) error {
	replyID = strings.TrimSpace(replyID)
	if replyID == "" {
		return fmt.Errorf("reply ID is required")
	}
	_, err := d.Exec(`
		UPDATE reply_events
		SET status = 'handled',
			assigned_to = CASE WHEN ? = '' THEN assigned_to ELSE ? END,
			handled_at = ?,
			created_at = created_at
		WHERE id = ?`,
		assignedTo, assignedTo, time.Now().UTC().Format(time.RFC3339), replyID,
	)
	return err
}

func ReopenReply(d *sql.DB, replyID string) error {
	replyID = strings.TrimSpace(replyID)
	if replyID == "" {
		return fmt.Errorf("reply ID is required")
	}
	_, err := d.Exec(`
		UPDATE reply_events
		SET status = 'open',
			handled_at = ''
		WHERE id = ?`,
		replyID,
	)
	return err
}

func SaveReplyDraft(d *sql.DB, replyID, draftReply, assignedTo string) (*ReplyEvent, error) {
	replyID = strings.TrimSpace(replyID)
	if replyID == "" {
		return nil, fmt.Errorf("reply ID is required")
	}
	_, err := d.Exec(`
		UPDATE reply_events
		SET draft_reply = ?,
			assigned_to = CASE WHEN ? = '' THEN assigned_to ELSE ? END
		WHERE id = ?`,
		draftReply, assignedTo, assignedTo, replyID,
	)
	if err != nil {
		return nil, err
	}
	return replyEventByID(d, replyID)
}

// ReclassifyReply updates a reply event's classification and re-runs the
// cascading logic (enrollment status, task cancellation, suppression).
// Returns the old classification so callers can track changes.
func ReclassifyReply(d *sql.DB, replyID, newClassification string) (oldClassification string, err error) {
	event, err := replyEventByID(d, replyID)
	if err != nil {
		return "", err
	}
	normalized := normalizeReplyClassification(newClassification)
	if normalized == event.Classification {
		return event.Classification, nil // no change
	}
	oldClassification = event.Classification

	tx, err := d.Begin()
	if err != nil {
		return "", fmt.Errorf("beginning reclassify transaction: %w", err)
	}
	defer tx.Rollback()

	// Update the reply event classification
	if _, err := tx.Exec(`UPDATE reply_events SET classification = ?, status = ? WHERE id = ?`,
		normalized, replyStatus(normalized), replyID); err != nil {
		return "", fmt.Errorf("updating reply classification: %w", err)
	}

	// Re-run cascading logic for the new classification
	contactEmail := strings.ToLower(strings.TrimSpace(event.ContactEmail))

	enrollmentStatus := StatusPaused
	statusReason := "reply:" + normalized
	if normalized == "not_interested" || normalized == "unsubscribe" || normalized == "bounced" {
		enrollmentStatus = StatusStopped
	}

	if _, err := tx.Exec(`
		UPDATE sequence_enrollments
		SET status = ?, status_reason = ?, reply_state = ?, updated_at = datetime('now')
		WHERE lower(contact_email) = lower(?) AND status IN (?, ?, ?)`,
		enrollmentStatus, statusReason, normalized, contactEmail,
		StatusActive, StatusPaused, StatusStopped); err != nil {
		return "", fmt.Errorf("updating enrollments: %w", err)
	}

	// Cancel open tasks if stopping
	if enrollmentStatus == StatusStopped {
		if _, err := tx.Exec(`
			UPDATE follow_up_tasks
			SET status = ?, canceled_reason = ?, updated_at = datetime('now')
			WHERE enrollment_id IN (
				SELECT id FROM sequence_enrollments WHERE lower(contact_email) = lower(?)
			) AND status = ?`,
			TaskStatusCanceled, statusReason, contactEmail, TaskStatusOpen); err != nil {
			return "", fmt.Errorf("canceling tasks: %w", err)
		}

		// Add suppression
		if _, err := tx.Exec(`
			INSERT INTO suppressions (id, scope, value, reason, source)
			VALUES (?, 'email', ?, ?, 'reply')
			ON CONFLICT(scope, value) DO UPDATE SET reason = excluded.reason, source = excluded.source`,
			newID("sup"), contactEmail, statusReason); err != nil {
			return "", fmt.Errorf("adding suppression: %w", err)
		}
	}

	// Handle referral: extract and create contact
	if normalized == "referral" {
		refEmail, refName := extractReferral(event.Snippet)
		if refEmail != "" {
			if _, err := tx.Exec(`UPDATE reply_events SET referred_email = ?, referred_name = ? WHERE id = ?`,
				refEmail, refName, replyID); err != nil {
				return "", fmt.Errorf("storing referral metadata: %w", err)
			}
			refDomain := domainFromEmail(refEmail)
			if _, err := tx.Exec(`
				INSERT INTO contacts (id, source, source_id, email, name, domain, lead_status)
				VALUES (?, 'referral', ?, ?, ?, ?, 'referred')
				ON CONFLICT(source, email) DO NOTHING`,
				newID("con"), contactEmail, refEmail, refName, refDomain); err != nil {
				return "", fmt.Errorf("creating referral contact: %w", err)
			}
		}
	}

	if err := tx.Commit(); err != nil {
		return "", fmt.Errorf("committing reclassify: %w", err)
	}
	return oldClassification, nil
}

func replyEventByID(d *sql.DB, replyID string) (*ReplyEvent, error) {
	row := d.QueryRow(`
		SELECT id, enrollment_id, mailbox_id, thread_id, message_id, contact_email, classification,
			status, assigned_to, subject, snippet, draft_reply, handled_at, occurred_at
		FROM reply_events
		WHERE id = ?`,
		replyID,
	)
	var item ReplyEvent
	if err := row.Scan(
		&item.ID, &item.EnrollmentID, &item.MailboxID, &item.ThreadID, &item.MessageID, &item.ContactEmail,
		&item.Classification, &item.Status, &item.AssignedTo, &item.Subject, &item.Snippet, &item.DraftReply,
		&item.HandledAt, &item.OccurredAt,
	); err != nil {
		if err == sql.ErrNoRows {
			return nil, fmt.Errorf("reply event %q not found", replyID)
		}
		return nil, err
	}
	item.NeedsAction = item.Status == "open"
	return &item, nil
}

