  1→import { v } from "convex/values";
  2→import { internalAction, internalMutation } from "./_generated/server";
  3→import { internal } from "./_generated/api";
  4→import { generateId } from "./helpers";
  5→
  6→// Shared Unipile send helper — used by both cron dispatcher and sync httpAction
  7→export async function callUnipileSend(args: {
  8→  accountId: string;
  9→  to: string;
 10→  subject: string;
 11→  body: string;
 12→  replyTo?: string;
 13→}): Promise<
 14→  | { ok: true; messageId: string; providerId: string }
 15→  | { ok: false; error: string; authError: boolean }
 16→> {
 17→  const apiKey = process.env.UNIPILE_API_KEY;
 18→  const apiUrl = process.env.UNIPILE_API_URL;
 19→  if (!apiKey || !apiUrl) {
 20→    return { ok: false, error: "Unipile API key or URL not configured", authError: false };
 21→  }
 22→
 23→  const payload: Record<string, any> = {
 24→    account_id: args.accountId,
 25→    to: [{ identifier: args.to }],
 26→    subject: args.subject,
 27→    body: args.body,
 28→  };
 29→
 30→  if (args.replyTo) {
 31→    payload.reply_to = args.replyTo;
 32→  }
 33→
 34→  // Add 30s timeout to Unipile fetch call
 35→  const controller = new AbortController();
 36→  const timeoutId = setTimeout(() => controller.abort(), 30000);
 37→
 38→  let resp: Response;
 39→  try {
 40→    resp = await fetch(`${apiUrl}/api/v1/emails`, {
 41→      method: "POST",
 42→      headers: {
 43→        "X-API-KEY": apiKey,
 44→        "Content-Type": "application/json",
 45→      },
 46→      body: JSON.stringify(payload),
 47→      signal: controller.signal,
 48→    });
 49→  } catch (fetchError: any) {
 50→    clearTimeout(timeoutId);
 51→    if (fetchError.name === "AbortError") {
 52→      return { ok: false, error: "Unipile API request timed out (30s)", authError: false };
 53→    }
 54→    return { ok: false, error: `Unipile API fetch error: ${fetchError.message}`, authError: false };
 55→  }
