 43→func ListSuppressions(d *sql.DB, scope string, limit int) ([]Suppression, error) {
 44→	query := `SELECT id, scope, value, reason, source, created_at FROM suppressions`
 45→	var args []any
 46→	if scope != "" {
 47→		query += ` WHERE scope = ?`
 48→		args = append(args, normalizeSuppressionScope(scope))
 49→	}
 50→	query += ` ORDER BY created_at DESC`
 51→	if limit > 0 {
 52→		query += " LIMIT ?"
 53→		args = append(args, limit)
 54→	}
 55→
 56→	rows, err := d.Query(query, args...)
 57→	if err != nil {
 58→		return nil, err
 59→	}
 60→	defer rows.Close()
 61→
 62→	var suppressions []Suppression
 63→	for rows.Next() {
 64→		var item Suppression
 65→		if err := rows.Scan(&item.ID, &item.Scope, &item.Value, &item.Reason, &item.Source, &item.CreatedAt); err != nil {
 66→			return nil, err
 67→		}
 68→		suppressions = append(suppressions, item)
 69→	}
 70→	return suppressions, rows.Err()
 71→}
