 77→	}
 78→	if !strings.Contains(email, "@") {
 79→		return nil, false, fmt.Errorf("invalid email format: %q", email)
 80→	}
 81→
 82→	if suppression, err := suppressionByScopeValue(d, "email", email); err == nil {
 83→		return suppression, true, nil
 84→	} else if !isNotFound(err) {
 85→		return nil, false, err
 86→	}
 87→
 88→	domain := domainFromEmail(email)
