 90→		return nil, false, nil
 91→	}
 92→	if suppression, err := suppressionByScopeValue(d, "domain", domain); err == nil {
 93→		return suppression, true, nil
 94→	} else if !isNotFound(err) {
 95→		return nil, false, err
 96→	}
 97→
 98→	return nil, false, nil
