import { v } from "convex/values";
import { mutation } from "./_generated/server";
import { nextSyncVersion } from "./helpers";

// Status priority: stopped > completed > paused > active
const STATUS_PRIORITY: Record<string, number> = {
  active: 0,
  paused: 1,
  completed: 2,
  stopped: 3,
};

// Create enrollment + drafts after first touch send intent
export const createEnrollment = mutation({
  args: {
    userId: v.string(),
    enrollment: v.object({
      externalId: v.string(),
      sequenceName: v.string(),
      campaignName: v.optional(v.string()),
      mailboxId: v.string(),
      contactEmail: v.string(),
      contactName: v.optional(v.string()),
      subject: v.optional(v.string()),
      threadId: v.optional(v.string()),
      lastMessageId: v.optional(v.string()),
      currentStep: v.float64(),
      totalSteps: v.float64(),
      initialBody: v.optional(v.string()),
      unipileThreadProviderId: v.optional(v.string()),
      unipileAccountId: v.optional(v.string()),
    }),
    task: v.object({
      externalId: v.string(),
      stepNumber: v.float64(),
      stepName: v.optional(v.string()),
      sendType: v.string(),
      dueAt: v.string(),
      subject: v.optional(v.string()),
      body: v.optional(v.string()),
    }),
    drafts: v.array(
      v.object({
        externalId: v.string(),
        taskId: v.string(),
        stepNumber: v.float64(),
        subject: v.optional(v.string()),
        body: v.optional(v.string()),
        channel: v.string(),
        generatedBy: v.optional(v.string()),
        generatedContext: v.optional(v.string()),
      })
    ),
  },
  handler: async (ctx, args) => {
    const version = await nextSyncVersion(ctx, args.userId);

    // Create enrollment
    await ctx.db.insert("sequenceEnrollments", {
      ...args.enrollment,
      status: "active",
      statusReason: "",
      replyState: "",
      lastSentAt: new Date().toISOString(),
      nextDueAt: args.task.dueAt,
      syncVersion: version,
      userId: args.userId,
    });

    // Create first follow-up task
    await ctx.db.insert("followUpTasks", {
      externalId: args.task.externalId,
      enrollmentId: args.enrollment.externalId,
      mailboxId: args.enrollment.mailboxId,
      contactEmail: args.enrollment.contactEmail,
      subject: args.task.subject,
      body: args.task.body,
      threadId: args.enrollment.threadId,
      stepNumber: args.task.stepNumber,
      stepName: args.task.stepName,
      sendType: args.task.sendType,
      status: "open",
      sendStatus: "pending",
      dueAt: args.task.dueAt,
      attemptCount: 0,
      syncVersion: version,
      userId: args.userId,
    });

    // Create drafts for future steps
    for (const draft of args.drafts) {
      await ctx.db.insert("sequenceDrafts", {
        externalId: draft.externalId,
        enrollmentId: args.enrollment.externalId,
        taskId: draft.taskId,
        stepNumber: draft.stepNumber,
        subject: draft.subject,
        body: draft.body,
        channel: draft.channel,
        status: "pending",
        generatedBy: draft.generatedBy,
        generatedContext: draft.generatedContext,
        syncVersion: version,
        userId: args.userId,
      });
    }

    return { enrollmentId: args.enrollment.externalId, version };
  },
});

// Stop enrollment with status priority enforcement
export const stopEnrollment = mutation({
  args: {
    userId: v.string(),
    enrollmentId: v.string(),
    reason: v.optional(v.string()),
    addSuppression: v.optional(
      v.object({
        scope: v.string(),
        value: v.string(),
        reason: v.optional(v.string()),
        source: v.string(),
        externalId: v.string(),
      })
    ),
  },
  handler: async (ctx, args) => {
    const version = await nextSyncVersion(ctx, args.userId);

    const enrollment = await ctx.db
      .query("sequenceEnrollments")
      .withIndex("by_external_id", (q) => q.eq("externalId", args.enrollmentId))
      .first();

    if (!enrollment) {
      throw new Error(`Enrollment ${args.enrollmentId} not found`);
    }

    // Status priority check
    const currentPriority = STATUS_PRIORITY[enrollment.status] ?? 0;
    const newPriority = STATUS_PRIORITY["stopped"] ?? 3;
    if (currentPriority >= newPriority) {
      return { already: enrollment.status };
    }

    await ctx.db.patch(enrollment._id, {
      status: "stopped",
      statusReason: args.reason || "manual stop",
      nextDueAt: "",
      syncVersion: version,
    });

    // Cancel all pending tasks for this enrollment
    const tasks = await ctx.db
      .query("followUpTasks")
      .withIndex("by_enrollment", (q) => q.eq("enrollmentId", args.enrollmentId))
      .collect();

    for (const task of tasks) {
      if (task.status === "open" && task.sendStatus === "pending") {
        await ctx.db.patch(task._id, {
          status: "canceled",
          sendStatus: "canceled",
          canceledReason: args.reason || "enrollment stopped",
          syncVersion: version,
        });
      }
    }

    // Cancel pending drafts
    const drafts = await ctx.db
      .query("sequenceDrafts")
      .withIndex("by_enrollment", (q) => q.eq("enrollmentId", args.enrollmentId))
      .collect();

    for (const draft of drafts) {
      if (draft.status === "pending") {
        await ctx.db.patch(draft._id, {
          status: "canceled",
          syncVersion: version,
        });
      }
    }

    // Optionally add suppression
    if (args.addSuppression) {
      await ctx.db.insert("suppressions", {
        externalId: args.addSuppression.externalId,
        scope: args.addSuppression.scope,
        value: args.addSuppression.value,
        reason: args.addSuppression.reason || "",
        source: args.addSuppression.source,
        syncVersion: version,
        userId: args.userId,
      });
    }

    return { stopped: true, version };
  },
});

// Pause enrollment
export const pauseEnrollment = mutation({
  args: {
    userId: v.string(),
    enrollmentId: v.string(),
  },
  handler: async (ctx, args) => {
    const version = await nextSyncVersion(ctx, args.userId);

    const enrollment = await ctx.db
      .query("sequenceEnrollments")
      .withIndex("by_external_id", (q) => q.eq("externalId", args.enrollmentId))
      .first();

    if (!enrollment) {
      throw new Error(`Enrollment ${args.enrollmentId} not found`);
    }

    // Status priority: can only pause if currently active
    if (STATUS_PRIORITY[enrollment.status] > STATUS_PRIORITY["paused"]) {
      return { rejected: true, currentStatus: enrollment.status };
    }

    await ctx.db.patch(enrollment._id, {
      status: "paused",
      statusReason: "manual pause",
      syncVersion: version,
    });

    return { paused: true, version };
  },
});

// Resume enrollment
export const resumeEnrollment = mutation({
  args: {
    userId: v.string(),
    enrollmentId: v.string(),
  },
  handler: async (ctx, args) => {
    const version = await nextSyncVersion(ctx, args.userId);

    const enrollment = await ctx.db
      .query("sequenceEnrollments")
      .withIndex("by_external_id", (q) => q.eq("externalId", args.enrollmentId))
      .first();

    if (!enrollment) {
      throw new Error(`Enrollment ${args.enrollmentId} not found`);
    }

    if (enrollment.status !== "paused") {
      return { rejected: true, currentStatus: enrollment.status };
    }

    await ctx.db.patch(enrollment._id, {
      status: "active",
      statusReason: "",
      syncVersion: version,
    });

    return { resumed: true, version };
  },
});

