import { v } from "convex/values";
import { httpAction, internalQuery, internalMutation } from "./_generated/server";
import type { ActionCtx } from "./_generated/server";
import { api, internal } from "./_generated/api";
import { generateId } from "./helpers";

// Payload interfaces for webhook events
interface WebhookEmailData {
  provider_id?: string;
  account_id?: string;
  from?: { identifier?: string };
  from_email?: string;
  thread_id?: string;
  id?: string;
  subject?: string;
  body_plain?: string;
  status?: string;
}

interface WebhookPayload extends WebhookEmailData {
  event?: string;
  type?: string;
  data?: WebhookEmailData;
}

interface AccountCallbackPayload {
  account_id?: string;
  name?: string;
  identifier?: string;
}

// Constant-time string comparison to prevent timing attacks on secret values.
// Folds the length difference into the result instead of early-returning,
// so the comparison always takes the same time regardless of input lengths.
export function timingSafeEqual(a: string, b: string): boolean {
  const encoder = new TextEncoder();
  const bufA = encoder.encode(a);
  const bufB = encoder.encode(b);
  const maxLen = Math.max(bufA.length, bufB.length);
  let result = bufA.length ^ bufB.length; // non-zero if lengths differ
  for (let i = 0; i < maxLen; i++) {
    result |= (bufA[i] || 0) ^ (bufB[i] || 0);
  }
  return result === 0;
}

// Unipile webhook receiver — handles new emails, tracking, account status
export const unipileWebhook = httpAction(async (ctx, request) => {
  // Verify Unipile-Auth shared secret (required)
  const secret = process.env.UNIPILE_WEBHOOK_SECRET;
  if (!secret) {
    console.error("UNIPILE_WEBHOOK_SECRET not configured - rejecting all webhooks");
    return new Response("Server misconfigured", { status: 500 });
  }

  const authHeader = request.headers.get("Unipile-Auth");
  if (!authHeader || !timingSafeEqual(authHeader, secret)) {
    console.error("Webhook auth failed: missing or invalid Unipile-Auth header");
    return new Response("Unauthorized", { status: 401 });
  }

  const contentType = request.headers.get("content-type") || "";
  if (!contentType.includes("application/json")) {
    return new Response("Content-Type must be application/json", { status: 415 });
  }

  try {
    const payload = await request.json();
    const eventType = payload.event || payload.type;

    switch (eventType) {
      case "new_email":
      case "mail.received":
        await handleNewEmail(ctx, payload);
        break;

      case "email_tracking":
      case "mail.tracking":
        // Log open/click events — useful for analytics
        console.log("Email tracking event:", JSON.stringify(payload));
        break;

      case "account.status":
      case "account_status":
        await handleAccountStatus(ctx, payload);
        break;

      default:
        console.log("Unknown webhook event:", eventType, JSON.stringify(payload));
    }

    return new Response("OK", { status: 200 });
  } catch (error: unknown) {
    const message = error instanceof Error ? error.message : String(error);
    console.error("Webhook processing error:", message);
    return new Response("Internal error", { status: 500 });
  }
});

