// convex/crmWebhook.ts
//
// Receives deal stage change webhooks from HubSpot (and future CRMs).
// Extracts won/lost outcome and computes attribution back to Nurge sequences.

import { v } from "convex/values";
import {
  httpAction,
  internalMutation,
} from "./_generated/server";
import { internal } from "./_generated/api";

// ── HubSpot webhook handler ────────────────────────────────────────

export const hubspotDealWebhook = httpAction(async (ctx, request) => {
  const contentType = request.headers.get("content-type") || "";
  if (!contentType.includes("application/json")) {
    return new Response("Content-Type must be application/json", { status: 415 });
  }

  try {
    const rawBody = await request.text();

    // Verify HubSpot webhook signature (v3)
    const hubspotSecret = process.env.HUBSPOT_WEBHOOK_SECRET;
    if (hubspotSecret) {
      const signature = request.headers.get("X-HubSpot-Signature-v3");
      const timestamp = request.headers.get("X-HubSpot-Request-Timestamp");
      if (!signature || !timestamp) {
        return new Response("Missing signature headers", { status: 401 });
      }
      // Reject requests older than 5 minutes
      if (Math.abs(Date.now() - parseInt(timestamp)) > 300000) {
        return new Response("Request too old", { status: 401 });
      }
      const baseString = request.method + request.url + rawBody + timestamp;
      const encoder = new TextEncoder();
      const key = await crypto.subtle.importKey(
        "raw", encoder.encode(hubspotSecret),
        { name: "HMAC", hash: "SHA-256" }, false, ["sign"]
      );
      const sig = await crypto.subtle.sign("HMAC", key, encoder.encode(baseString));
      const computed = btoa(String.fromCharCode(...new Uint8Array(sig)));
      if (computed !== signature) {
        return new Response("Invalid signature", { status: 401 });
      }
    } else {
      console.warn("HUBSPOT_WEBHOOK_SECRET not set - HubSpot webhooks are unauthenticated");
    }

    const events = JSON.parse(rawBody);

    for (const event of events) {
      if (
        event.subscriptionType !== "deal.propertyChange" ||
        event.propertyName !== "dealstage"
      ) {
        continue;
      }

      const dealId = String(event.objectId);
      const newStage = event.propertyValue;

      // Validate newStage is a non-empty string
      if (!newStage || typeof newStage !== "string" || newStage.trim() === "") {
        console.log(`Skipping deal ${dealId}: empty or invalid dealstage value`);
        continue;
      }

      const outcome = mapHubSpotStage(newStage);
      if (!outcome) continue;

      await ctx.runMutation(internal.crmWebhook.recordOutcome, {
        crmDealId: dealId,
        outcome,
        source: "hubspot",
      });
    }

    return new Response("OK", { status: 200 });
  } catch (error: any) {
    console.error("HubSpot webhook error:", error.message || error, error.stack);
    return new Response("OK", { status: 200 });
  }
});

function mapHubSpotStage(stage: string): string | null {
  const normalized = stage.toLowerCase().replace(/[\s_]+/g, "");
  if (["closedwon", "won"].includes(normalized)) return "won";
  if (["closedlost", "lost"].includes(normalized)) return "lost";
  return null;
}

// ── Record outcome with attribution ─────────────────────────────────

export const recordOutcome = internalMutation({
  args: {
    crmDealId: v.string(),
    outcome: v.string(),
    source: v.string(),
  },
  handler: async (ctx, args) => {
    // Find the deal in our deals table
    const deal = await ctx.db
      .query("deals")
      .filter((q) => q.eq(q.field("sourceId"), args.crmDealId))
      .first();

    if (!deal) {
      console.log(`Deal ${args.crmDealId} not found in Nurge`);
      return;
    }

    const contactEmail = deal.contactEmail || "";

    if (!contactEmail) {
      console.warn(`Deal ${args.crmDealId} has no contactEmail, skipping outcome recording`);
      return;
    }

    // Deduplicate by crmDealId + outcome combination (not just contactEmail)
    const existingOutcomes = await ctx.db
      .query("dealOutcomes")
      .withIndex("by_contact", (q) =>
        q.eq("userId", deal.userId).eq("contactEmail", contactEmail)
      )
      .collect();
    const alreadyRecorded = existingOutcomes.some(
      (o) => o.sourceId === args.crmDealId && o.outcome === args.outcome
    );
    if (alreadyRecorded) {
      console.log(`Outcome ${args.outcome} already recorded for deal ${args.crmDealId}`);
      return;
    }

    // Find enrollment that sourced this deal
    const enrollment = contactEmail
      ? await ctx.db
          .query("sequenceEnrollments")
          .withIndex("by_contact", (q) =>
            q.eq("userId", deal.userId).eq("contactEmail", contactEmail)
          )
          .first()
      : null;

    // Find contact for persona info
    const contact = contactEmail
      ? await ctx.db
          .query("contacts")
          .withIndex("by_email", (q) =>
            q.eq("userId", deal.userId).eq("email", contactEmail)
          )
          .first()
      : null;

    if (!contact) {
      console.warn(`Contact not found for deal ${args.crmDealId} (email: ${contactEmail})`);
    }

    // Count touches
    let touchCount = 0;
    if (enrollment) {
      const tasks = await ctx.db
        .query("followUpTasks")
        .withIndex("by_enrollment", (q) =>
          q.eq("enrollmentId", enrollment.externalId)
        )
        .collect();
      touchCount = tasks.filter((t) => t.sendStatus === "sent").length;
    }

    // Days to close
    const closeDate = deal.closeDate || new Date().toISOString();
    let daysToClose: number | undefined;
    if (enrollment?.lastSentAt) {
      daysToClose = Math.round(
        (new Date(closeDate).getTime() -
          new Date(enrollment.lastSentAt).getTime()) /
          86400000
      );
